12	const PROCESSING_FEE = 5;
13	const BASE_PREMIUMS: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	};
17	const FIRST_INSURANCE_MULTIPLIER = 1.1;
18	
19	// Round up in MHPCO's favour, guarding against floating-point noise
20	// (e.g. 197.50000000001 should still round to 198, not 199).
21	const roundUpInMHPCOFavor = (amount: number): number =>
22	  Math.ceil(Number(amount.toFixed(6)));
23	
24	export const quote = (
25	  items: Item[],
26	  customer: Customer,
27	  contractIndex: number,
28	): number => {
29	  let policyBase = 0;
30	  for (const item of items) {
31	    policyBase += BASE_PREMIUMS[item.type] * FIRST_INSURANCE_MULTIPLIER;
32	  }
33	  const total = policyBase + PROCESSING_FEE;
34	  return roundUpInMHPCOFavor(total);
35	};
36	
37	export const claim = (): number => {
38	  return undefined as unknown as number;
39	};
